from typing import Dict, Optional


class MetadataHTMLParser(HTMLParser):
    """HTML parser to extract title and meta description from webpage."""

    def __init__(self) -> None:
        super().__init__()
        self.title: str = ""
        self.description: str = ""
        self.in_title: bool = False
        self.found_description: bool = False

    def handle_starttag(self, tag: str, attrs: list) -> None:
        if tag == "title":
            self.in_title = True
        elif tag == "meta":
            attrs_dict = dict(attrs)
            if (not self.found_description and 
                attrs_dict.get("name") == "description"):
                self.description = attrs_dict.get("content", "").strip()
                self.found_description = True

    def handle_data(self, data: str) -> None:
        if self.in_title:
            self.title += data

    def handle_endtag(self, tag: str) -> None:
        if tag == "title":
            self.in_title = False


def fetch_page_metadata(page_url: str) -> Dict[str, str]:
    """
    Fetch HTML content from a URL and extract title and description metadata.

    Args:
        page_url: A valid URL pointing to a public webpage.

    Returns:
        Dictionary containing the page title and description.
        Example: {'title': 'Example', 'description': 'An example page'}

    Raises:
        ValueError: If the URL is invalid or cannot be processed.
        urllib.error.URLError: If there's an error fetching the URL.
    """
    if not page_url or not isinstance(page_url, str):
        raise ValueError("page_url must be a non-empty string")

    # Add basic URL validation
    if not page_url.startswith(('http://', 'https://')):
        raise ValueError("URL must start with http:// or https://")

    headers = {
        'User-Agent': 'Mozilla/5.0 (compatible; SocialMediaScraper/1.0)'
    }

    try:
        req = urllib.request.Request(page_url, headers=headers)

        with urllib.request.urlopen(req, timeout=10) as response:
            # Check if response is HTML
            content_type = response.headers.get('Content-Type', '')
            if 'text/html' not in content_type:
                raise ValueError("URL does not point to an HTML page")

            html_content = response.read().decode('utf-8', errors='ignore')

    except urllib.error.HTTPError as e:
        raise urllib.error.URLError(f"HTTP Error {e.code}: {e.reason}")
    except urllib.error.URLError as e:
        raise urllib.error.URLError(f"URL Error: {e.reason}")
    except Exception as e:
        raise ValueError(f"Error fetching page: {str(e)}")

    # Parse HTML to extract metadata
    parser = MetadataHTMLParser()
    try:
        parser.feed(html_content)
    except Exception:
        # If parsing fails, return empty values
        pass

    # Clean up extracted values
    title = parser.title.strip() if parser.title else ""
    description = parser.description.strip() if parser.description else ""

    # Fallback: if no meta description found, try to find og:description
    if not description:
        # Simple search for og:description
        import re
        og_desc_match = re.search(
            r'<meta[^>]*property=["\']og:description["\'][^>]*content=["\']([^"\']+)["\']',
            html_content,
            re.IGNORECASE
        )
        if og_desc_match:
            description = og_desc_match.group(1).strip()

    return {
        'title': title[:500] if title else "",  # Limit title length
        'description': description[:1000] if description else ""  # Limit description length
    }

